async function main() {
  for (const [title, report_md] of Object.entries(ROADMAPS)) {
    const { error, count } = await supabase
      .from('biz_model_ideas')
      .update({ report_md, status: 'validating' }, { count: 'exact' })
      .eq('title', title);
    if (error) console.error(`✗ ${title}: ${error.message}`);
    else console.log(`✓ ${title} (${count}件更新)`);
  }
}

main();
